class FenwickTree {
  constructor(size) {
    this.n = size;
    this.tree = new Array(this.n + 1).fill(0);
  }

  update(index, delta) {
    index += 1; // 1-based index
    while (index <= this.n) {
      this.tree[index] += delta;
      index += index & -index;
    }
  }

  query(index) {
    index += 1; // 1-based index
    let res = 0;
    while (index > 0) {
      res += this.tree[index];
      index -= index & -index;
    }
    return res;
  }

  rangeQuery(l, r) {
    return this.query(r) - this.query(l - 1);
  }
}

function countSetBits(n) {
  let count = 0;
  while (n) {
    n &= n - 1;
    count++;
  }
  return count;
}

function getDepth(x) {
  let steps = 0;
  let current = x;
  while (current !== 1) {
    current = countSetBits(current);
    steps++;
  }
  return steps;
}

